import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../../services/api';

export default function Register() {
  const [form, setForm] = useState({ name: '', email: '', password: '', role: 'reporter' });
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await API.post('/auth/register', form);
      alert("Registration successful! Please login.");
      navigate('/login');
    } catch (err) {
      alert("Registration failed");
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-[80vh]">
      <form onSubmit={handleSubmit} className="bg-white p-8 rounded-3xl shadow-lg w-full max-w-md">
        <h2 className="text-2xl font-bold mb-6 text-center">Join the Mission</h2>
        <input type="text" placeholder="Full Name" className="w-full mb-4 p-4 border rounded-2xl" onChange={e => setForm({...form, name: e.target.value})} />
        <input type="email" placeholder="Email" className="w-full mb-4 p-4 border rounded-2xl" onChange={e => setForm({...form, email: e.target.value})} />
        <input type="password" placeholder="Password" className="w-full mb-4 p-4 border rounded-2xl" onChange={e => setForm({...form, password: e.target.value})} />
        <select className="w-full mb-6 p-4 border rounded-2xl" onChange={e => setForm({...form, role: e.target.value})}>
          <option value="reporter">I want to report incidents</option>
          <option value="volunteer">I am a Rescuer/NGO</option>
        </select>
        <button className="w-full bg-green-600 text-white py-4 rounded-2xl font-bold">Register</button>
      </form>
    </div>
  );
}
